package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "url field is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "failed to fetch url: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "failed to fetch url: status code " + string(rune(resp.StatusCode)),
		})
	}

	// Read response body with limit
	limitedReader := io.LimitReader(resp.Body, 1024*1024) // 1MB limit
	doc, err := html.Parse(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "failed to parse html: " + err.Error(),
		})
	}

	title, description := extractMetadata(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(n *html.Node) (string, string) {
	var title, description string

	var traverse func(*html.Node)
	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode {
			if node.Data == "title" && node.FirstChild != nil {
				title = node.FirstChild.Data
			}

			if node.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range node.Attr {
					if attr.Key == "name" {
						nameAttr = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = contentAttr
				}
			}
		}

		for child := node.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(n)
	return title, description
}

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

