	title, description := parseHTMLPreview(resp.Body)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTMLPreview(body io.Reader) (string, string) {
	var title string
	var description string

	tokenizer := html.NewTokenizer(body)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()

			// Extract title
			if token.Data == "title" {
				tokenizer.Next()
				title = tokenizer.Token().Data
			}

			// Extract meta description
			if token.Data == "meta" {
				var name string
				var content string

				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				if name == "description" && content != "" {
					description = content
				}
			}
		}
	}
}

