package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "URL field is required",
		})
	}

	title, description, err := fetchPageMetadata(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: err.Error(),
		})
	}

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func fetchPageMetadata(url string) (string, string, error) {
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(url)
	if err != nil {
		return "", "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", "", err
	}

	// Limit the body read to avoid excessive memory usage
	limitedBody := io.LimitReader(resp.Body, 1024*1024) // 1MB limit
	doc, err := html.Parse(limitedBody)
	if err != nil {
		return "", "", err
	}

	title := extractTitle(doc)
	description := extractMetaDescription(doc)

	return title, description, nil
}

func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
			return strings.TrimSpace(n.FirstChild.Data)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}

	return ""
}

func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var name, content string
		for _, attr := range n.Attr {
			if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
				name = attr.Val
			}
			if attr.Key == "content" {
				content = attr.Val
			}
		}
		if name != "" && content != "" {
			return strings.TrimSpace(content)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := extractMetaDescription(c); desc != "" {
			return desc
		}
	}

	return ""
}

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

