package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "HTTP status code: " + string(rune(resp.StatusCode)),
		})
	}

	// Parse HTML and extract title and meta description
	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTML(body io.Reader) (string, string) {
	var title string
	var description string

	tokenizer := html.NewTokenizer(body)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description

		case html.StartTagToken:
			token := tokenizer.Token()

			// Extract title
			if token.Data == "title" {
				tokenizer.Next()
				title = tokenizer.Token().Data
			}

			// Extract meta description
			if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}
	}
}

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

