// Request body
type PreviewRequest struct {
	URL string `json:"url" validate:"required,url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Validate host to prevent SSRF attacks
	if parsedURL.Hostname() == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL: missing hostname"})
	}

	// Prevent access to private IP ranges
	if isPrivateIP(parsedURL.Hostname()) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private IP ranges is not allowed"})
	}

	// Fetch the URL with strict timeout and size limits
	client := &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirects to prevent redirect loops
			if len(via) >= 5 {
				return http.ErrUseLastResponse
			}
			// Validate redirect URL to prevent SSRF
			if isPrivateIP(req.URL.Hostname()) {
				return fmt.Errorf("redirect to private IP not allowed")
			}
			return nil
		},
	}

	httpReq := &http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: http.Header{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	}
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Check Content-Type to ensure it's HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Limit response body size to prevent memory exhaustion (10MB)
	limitedReader := io.LimitReader(resp.Body, 10*1024*1024)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}
			if n.Data == "meta" && description == "" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						nameAttr = attr.Val
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

// isPrivateIP checks if the given hostname is a private IP address or localhost
func isPrivateIP(hostname string) bool {
	if hostname == "" {
		return true
	}

	// Check for localhost
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Parse as IP address
	ip := net.ParseIP(hostname)
	if ip == nil {
		// Not an IP address, allow it (DNS resolution will happen)
		return false
	}

	// Check for private IP ranges
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	return false
}

