	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL field is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "HTTP status code: " + string(rune(resp.StatusCode)),
		})
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to read response body",
		})
	}

	// Parse HTML
	title, description := extractMetadata(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(htmlContent string) (string, string) {
	var title string
	var description string

	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						nameAttr = attr.Val
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}

				if strings.ToLower(nameAttr) == "description" {
					description = contentAttr
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

