	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Content type must be HTML"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			if n.Data == "meta" {
				var nameAttr, propertyAttr, contentAttr string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "property":
						propertyAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}

				if (nameAttr == "description" || propertyAttr == "og:description") && contentAttr != "" {
					description = contentAttr
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

// isPrivateIP checks if the given hostname resolves to a private IP address
func isPrivateIP(hostname string) bool {
	// List of private/reserved IP ranges and hostnames to block
	privateHosts := map[string]bool{
		"localhost":       true,
		"127.0.0.1":       true,
		"::1":             true,
		"0.0.0.0":         true,
		"169.254.169.254": true, // AWS metadata service
	}

	if privateHosts[hostname] {
		return true
	}

	// Check for private IP ranges
	ip := net.ParseIP(hostname)
	if ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast()
	}

	return false
}

